// Parse the incoming message
const msg = $input.first().json.message.text || '';
const lower = msg.toLowerCase().trim();

let action = null;
let taskName = null;

// Parse done: / /done
if (lower.startsWith('done:') || lower.startsWith('/done ')) {
  action = 'done';
  taskName = msg.replace(/^done:|^\/done /i, '').trim();
}
// Parse add: / /add / task:
else if (lower.startsWith('add:') || lower.startsWith('/add ') || lower.startsWith('task:') || lower.startsWith('/task ')) {
  action = 'add';
  taskName = msg.replace(/^add:|^\/add |^task:|^\/task /i, '').trim();
}
// Parse /brief or brief
else if (lower === '/brief' || lower === 'brief') {
  action = 'brief';
}
// Parse /help
else if (lower === '/help' || lower === 'help') {
  action = 'help';
}
else {
  action = 'unknown';
}

return [{
  json: {
    action,
    taskName,
    rawMessage: msg,
    chatId: $input.first().json.message.chat.id
  }
}];

// Read TASKS.md and mark task as done
const fs = require('fs');
const path = '/data/Productivity/TASKS.md';
// NOTE: Replace /data/Productivity with the actual mounted path in your Railway config
// or use the absolute path on your local Mac: /Users/yohanloyer/Projects/Productivity/TASKS.md

const taskName = $input.first().json.taskName;
let content = '';

try {
  content = fs.readFileSync(path, 'utf8');
} catch(e) {
  return [{ json: { success: false, error: 'Could not read TASKS.md: ' + e.message, taskName } }];
}

// Try to find and mark the task done
// Matches: - [ ] Task name or - [>] Task name or - [!] Task name etc.
const taskRegex = new RegExp(`- \\[[^x]\\] \\*\\*${taskName.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')}\\*\\*`, 'i');
const taskRegexSimple = new RegExp(`- \\[[^x]\\] ${taskName.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')}`, 'i');

const today = new Date().toISOString().split('T')[0];
let newContent = content;
let found = false;

if (taskRegex.test(content)) {
  newContent = content.replace(taskRegex, (match) => match.replace(/\\[[^x]\\]/, `[x]`) + ` ✓ ${today}`);
  found = true;
} else if (taskRegexSimple.test(content)) {
  newContent = content.replace(taskRegexSimple, (match) => match.replace(/\\[[^x]\\]/, `[x]`) + ` ✓ ${today}`);
  found = true;
}

if (found) {
  fs.writeFileSync(path, newContent, 'utf8');
  return [{ json: { success: true, taskName, message: `✅ Marked done: *${taskName}*` } }];
} else {
  return [{ json: { success: false, taskName, message: `⚠️ Task not found: *${taskName}*\n\nTip: Make sure the name matches exactly, or check TASKS.md` } }];
}

// Append new task to TASKS.md inbox section
const fs = require('fs');
const path = '/data/Productivity/TASKS.md';
// NOTE: Replace with actual path

const taskName = $input.first().json.taskName;
let content = '';

try {
  content = fs.readFileSync(path, 'utf8');
} catch(e) {
  return [{ json: { success: false, error: 'Could not read TASKS.md: ' + e.message, taskName } }];
}

// Add to Inbox section, or create it
const newTask = `- [ ] **${taskName}** — added via Telegram`;

if (content.includes('## 📥 Inbox')) {
  content = content.replace('## 📥 Inbox', `## 📥 Inbox\n${newTask}`);
} else {
  // Append inbox section at end
  content += `\n\n## 📥 Inbox\n${newTask}\n`;
}

try {
  fs.writeFileSync(path, content, 'utf8');
  return [{ json: { success: true, taskName, message: `📝 Task added: *${taskName}*\n\nIt's in your Inbox — open dashboard to assign it to a project.` } }];
} catch(e) {
  return [{ json: { success: false, error: e.message, taskName } }];
}
